import React, { useState, useEffect, useRef } from 'react';

const images = [
  '/images/login-1.jpg',
  '/images/login-2.jpg',
  '/images/chat-screen-1.jpg',
  '/images/outcoming-1.jpg',
  '/images/outcoming-2.jpg',
];

function TechGlobeSection() {
  const [currentImage, setCurrentImage] = useState(0);
  const [showImg, setShowImg] = useState(true);
  const [vidIndex, setVidIndex] = useState(0);
  const [vidShow, setVidShow] = useState(true);
  const v1 = useRef(null);
  const v2 = useRef(null);

  useEffect(() => {
    const id = setInterval(() => {
      setShowImg(false);
      setTimeout(() => {
        setCurrentImage(p => (p + 1) % images.length);
        setShowImg(true);
      }, 400);
    }, 2500);
    return () => clearInterval(id);
  }, []);

  function onV1End() {
    setVidShow(false);
    setTimeout(() => {
      setVidIndex(1);
      setVidShow(true);
      setTimeout(() => {
        if (v2.current) { v2.current.currentTime = 0; v2.current.play().catch(() => {}); }
      }, 50);
    }, 400);
  }

  function onV2Time() {
    if (v2.current && v2.current.currentTime >= 4) {
      v2.current.pause();
      setVidShow(false);
      setTimeout(() => {
        setVidIndex(0);
        setVidShow(true);
        setTimeout(() => {
          if (v1.current) { v1.current.currentTime = 0; v1.current.play().catch(() => {}); }
        }, 50);
      }, 400);
    }
  }

  return (
    <section className="py-20 px-4 sm:px-6 lg:px-8 bg-white overflow-hidden">
      <style>{`
        @keyframes rvIn { from { clip-path: inset(50% 50% 50% 50% round 12px); } to { clip-path: inset(0 0 0 0 round 12px); } }
        @keyframes rvOut { from { clip-path: inset(0 0 0 0 round 12px); } to { clip-path: inset(50% 50% 50% 50% round 12px); } }
      `}</style>
      <div className="max-w-7xl mx-auto">
        <div className="text-center mb-12">
          <h2 className="text-4xl font-bold text-gray-900 mb-4">Sản Phẩm Của Chúng Tôi</h2>
          <p className="text-gray-500 text-lg">Xem demo trực tiếp sản phẩm đã triển khai</p>
        </div>

        <div className="rounded-3xl p-6 lg:p-10" style={{
          background: 'linear-gradient(135deg, #0f1029 0%, #1a1040 50%, #0d0e2a 100%)',
          boxShadow: '0 25px 80px rgba(0,0,0,0.3), inset 0 1px 0 rgba(255,255,255,0.05)',
          border: '1px solid rgba(255,255,255,0.06)',
        }}>
          <div className="flex flex-col lg:flex-row gap-6 items-stretch justify-center" style={{ minHeight: '500px' }}>
            {/* Video side - full height */}
            <div className="w-full lg:w-3/5 flex items-center justify-center">
              <div className="w-full h-full" style={{
                animation: vidShow ? 'rvIn 0.4s ease-out forwards' : 'rvOut 0.3s ease-in forwards',
              }}>
                {vidIndex === 0 && (
                  <div className="rounded-xl overflow-hidden h-full" style={{ background: '#000' }}>
                    <video ref={v1} className="w-full h-full object-contain" autoPlay muted playsInline onEnded={onV1End} src="/videos/video-laptop.mp4" />
                  </div>
                )}
                {vidIndex === 1 && (
                  <div className="rounded-xl overflow-hidden h-full flex justify-center" style={{ background: '#000' }}>
                    <video ref={v2} className="h-full object-contain" muted playsInline onTimeUpdate={onV2Time} src="/videos/send-images.mp4" />
                  </div>
                )}
              </div>
            </div>

            {/* Image side - full height */}
            <div className="w-full lg:w-2/5 flex items-center justify-center">
              <div className="h-full w-full max-w-xs" style={{ position: 'relative', minHeight: '500px' }}>
                <img
                  src={images[currentImage]}
                  alt="App screenshot"
                  className="w-full h-full object-contain rounded-xl"
                  style={{
                    animation: showImg ? 'rvIn 0.4s ease-out forwards' : 'rvOut 0.3s ease-in forwards',
                  }}
                />
              </div>
            </div>
          </div>
        </div>
      </div>
    </section>
  );
}

export default TechGlobeSection;
